local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxQuestCtrl:LxBaseCtrl
local LxQuestCtrl = classX("LxQuestCtrl", LxBaseCtrl)

function LxQuestCtrl:Initialize()
    LxBaseCtrl.Initialize(self)

    self._initMainQuestList = nil
    self._initMainQuesBelongtList = nil
    self._jumpToCityMonsterTimer = nil
end

function LxQuestCtrl:Dispose()
    if(self._jumpToCityMonsterTimer)then
        MgrCenter.TimerMgr:RemoveTimer(self._jumpToCityMonsterTimer)
    end
    LxBaseCtrl.Dispose(self)
end

