end

--- 获取主线任务列表
function LxQuestCtrl:GetMainQuestList()
    if not self._initMainQuestList then
        self._initMainQuestList = {}
        for k,v in pairs(GameTable.MissionRef) do
            if v.type == QuestTypeEnum.Main then
                table.insert(self._initMainQuestList,v)
            end
        end
        table.sort(self._initMainQuestList,function(a,b)
            return a.sort < b.sort
        end)
    end
    return self._initMainQuestList
end

--- 主线任务归属区分
function LxQuestCtrl:GetMainQuestBelongList()
    if not self._initMainQuesBelongtList then
        local initMainQuesBelongtMap = {}
        local initMainQuestList = self:GetMainQuestList()
        local belong,belongType,chapterId
        for i,v in ipairs(initMainQuestList) do
            belong = string.split(v.belong,"=")
            belongType = checknumber(belong[1])
            if belongType == QuestTypeEnum.Main then
                chapterId = checknumber(belong[2])
                local mainQuestBelongList = initMainQuesBelongtMap[chapterId]
                if not mainQuestBelongList then
                    mainQuestBelongList = {}
                    initMainQuesBelongtMap[chapterId] = mainQuestBelongList
                end
                table.insert(mainQuestBelongList,{
                    questId = v.refId,
                })
            end
        end
        local list = {}
        for k,v in pairs(initMainQuesBelongtMap) do
            table.insert(list,{
                questList = v,
                name = LxDataHelper.GetInsWorldName(k),
                sort = LxDataHelper.GetInsWorldSort(k),
                chapterId = k,
            })
        end
        table.sort(list,function(a,b) return a.sort < b.sort end)
        self._initMainQuesBelongtList = list
    end
    return self._initMainQuesBelongtList
end

function LxQuestCtrl:GetAllQuestStatus()
    local questList = {}
    ---@type LxQuestObj
    local questObj = nil
    local questId
    local targetQuestId
    local list = CtrlCenter.Quest:GetMainQuestBelongList()
    for i,v in ipairs(list) do
        for idx,val in ipairs(v.questList) do
            questId = val.questId
            questObj = ModuleCenter.Quest:GetQuest(questId)
            if questObj then
                table.insert(questList,{
                    refId = questId,
                    state = questObj.state,
                })
                if not targetQuestId then
                    targetQuestId = questId
                end
            else
                table.insert(questList,{
                    refId = questId,
                    state = -1,
                })
            end
        end
    end
    table.sort(questList,function(a, b)
        local sortA = LxDataHelper.GetQuestSort(a.refId)
        local sortB = LxDataHelper.GetQuestSort(b.refId)
        return sortA < sortB
    end)
    if not targetQuestId then
        targetQuestId = questList[1].refId
    end
    local state
    local refId
    local dataList = {}
    for i,v in ipairs(questList) do
        refId = v.refId
        state = v.state
        if targetQuestId > refId then
            state = 2
        end
        dataList[refId] = {
            refId = v.refId,
            state = state,
        }
    end

    return dataList
end

function LxQuestCtrl:GetQuestList(questList)
    local parseQuestRewardList = self._parseQuestRewardList
    if not parseQuestRewardList then
        parseQuestRewardList = {}
        self._parseQuestRewardList = parseQuestRewardList
    end
    local allQuestStatusList = self:GetAllQuestStatus()
    local list = {}
    ---@type LxQuestObj
    local questObj
    ---@type V_QuestRef
    local questRef
    local questId,state
    local canGet,isGet,lock,noFinish = false,false,false,false
    local GetTxtStr,FinishTxtStr,NoFinishStr,ScheduleTxtStr,LockStr = "","","","",""
    local progress,goal = 0,0
    for i,v in ipairs(questList) do
        questId = v.questId
        questObj = ModuleCenter.Quest:GetQuest(questId)
        questRef = GameTable.MissionRef[questId]
        canGet,isGet,lock,noFinish = false,false,false,false
        GetTxtStr,FinishTxtStr,NoFinishStr,ScheduleTxtStr,LockStr = "","","","",""
        progress,goal = 0,0
        if questObj then
            state = questObj.state
            progress,goal = questObj.progress,questObj.goal
            canGet = state == 1
            isGet = state == 2
            if state == 0 then
                if goal == 1 then
                    noFinish = true
                    NoFinishStr = I18nText(6110)
                else
                    ScheduleTxtStr = string.replace(I18nText(6109),progress,goal)
                end
            end
        else
            if allQuestStatusList[questId] and allQuestStatusList[questId].state == 2 then
                isGet = true
            else
                lock = true
                LockStr = I18nText(questRef.unlockDesc)
            end
        end
        if canGet then GetTxtStr = I18nText(6107) end
        if isGet then FinishTxtStr = I18nText(6108) end
        local rewardList = {}
        if parseQuestRewardList[questId] then
            local trewardList = parseQuestRewardList[questId]
            for _i,_v in ipairs(trewardList) do
                table.insert(rewardList,{
                    rewardInfo = _v.rewardInfo,
                    showRed = canGet,
                    isGet = isGet,
                    questId = _v.questId,
                })
            end
        else
            local reward = questRef and questRef.reward or {}
            if #reward > 0 then
                local _rewardList = LxDataHelper.ParseItemList(reward)
                for idx,val in ipairs(_rewardList) do
                    table.insert(rewardList,{
                        rewardInfo = val,
                        showRed = canGet,
                        isGet = isGet,
                        questId = questId,
                    })
                end
                parseQuestRewardList[questId] = rewardList
            end
        end
        table.insert(list,{
            questId = questId,
            state = state,
            progress = progress,
            goal = goal,
            canGet = canGet,
            noFinish = noFinish,
            isGet = isGet,
            lock = lock,
            name = I18nText(questRef.name),
            description = I18nText(questRef.description),
            rewardList = rewardList,
            GetTxtStr = GetTxtStr,
            FinishTxtStr = FinishTxtStr,
            NoFinishStr = NoFinishStr,
            ScheduleTxtStr = ScheduleTxtStr,
            LockStr = LockStr,
        })
    end
    return list
end


function LxQuestCtrl:CheckQuestIsCanGet(refId)
    ---@type LxQuestObj
    local questObj = ModuleCenter.Quest:GetQuest(refId)
    if not questObj then return false end
    return questObj.state == 1
end

function LxQuestCtrl:GetQuestProgress(refId)
    ---@type LxQuestObj
    local questObj = ModuleCenter.Quest:GetQuest(refId)
    local goal = 0
    local ref = GameTable.MissionRef[refId]
    local finishCondArr = string.split(ref.finish, "=")
    local strArr = string.split(finishCondArr[2], ",")
    local len = 1
    if not questObj then
        local progress, goal = checknumber(strArr[len]), checknumber(strArr[len])
        return progress,goal
    end
    return questObj.progress,questObj.goal
end

function LxQuestCtrl:GetQuestState(refId)
    ---@type LxQuestObj
    local questObj = ModuleCenter.Quest:GetQuest(refId)
    if not questObj then return RewardStateEnums.HadGet end
    return questObj.state
end

--是否完成所有章节任务
function LxQuestCtrl:CheckFinallyAllChapterTask()
    local allChapterIds = ModuleCenter.Quest:GetAllChapterId()
    table.sort(allChapterIds,function(a,b)
        return a < b
    end)
    if #allChapterIds > 0 then
        local maxChapterId = allChapterIds[#allChapterIds]
        local chapterRef = GameTable.QuestStoryRef[maxChapterId]
        if chapterRef and chapterRef.next == -1 then
            return true
        end
    end
    return false
end

function LxQuestCtrl:GetChapterTaskId()
    local allChapterIds = ModuleCenter.Quest:GetAllChapterId()
    table.sort(allChapterIds,function(a,b)
        return a < b
    end)
    if #allChapterIds > 0 then
        local maxChapterId = allChapterIds[#allChapterIds]
        local chapterRef = GameTable.QuestStoryRef[maxChapterId]
        if chapterRef then
            if chapterRef.next == -1 then
                return maxChapterId
            else
                return chapterRef.next
            end
        end
    end
    return 1
end

function LxQuestCtrl:CheckChapterTaskFinish(chapterId)
    local chapterRef = GameTable.QuestStoryRef[chapterId]
    if chapterRef then
        local questions = chapterRef.questions
        if questions then
            for i = 1,#questions do
                local taskId = checknumber(questions[i])
                if self:GetQuestState(taskId) ~= RewardStateEnums.HadGet then
                    return false
                end
            end
            return true
        else
            return false
        end
    end
    return false
end

function LxQuestCtrl:CheckChapterIdFinish(chapterId)
    local allChapterIds = ModuleCenter.Quest:GetAllChapterId()
    for i = 1,#allChapterIds do
        if allChapterIds[i] == chapterId then
            return true
        end
    end
    return false
end

function LxQuestCtrl:GetMainQuestTaskInfo()
    local finallyChapterTask = self:CheckFinallyAllChapterTask()
    local showTaskInfo = {}
    if finallyChapterTask then
        local maskTaskInfo = self:GetMainTaskInfo()
        local showMainTask = false
        local mainT = {}
        if maskTaskInfo then
            if maskTaskInfo.state == RewardStateEnums.CanGet then
                showMainTask = true
            end
            local taskId = maskTaskInfo.refId
            local cfg = GameTable.MissionRef[taskId]
            local state = self:GetQuestState(taskId)
            local progress,goal = self:GetQuestProgress(taskId)
            local sort = 2
            if state == RewardStateEnums.CanGet then
                sort = 3
            elseif state == RewardStateEnums.HadGet then
                sort = 1
            end
            table.insert(mainT,{taskId = taskId,taskDes = I18nText(cfg.description),sortId = cfg.sort, progress = progress,goal = goal,sort = sort,state = state})
            local task = mainT[1]
            local color
            if task.state == RewardStateEnums.Normal then
                color = "#ff6666"
            else
                color = "#15660a"
            end
            showTaskInfo.showTaskInfo = string.replace(I18nText(10002),task.taskDes,color,task.progress,task.goal)
            showTaskInfo.questTaskId = task.taskId
            showTaskInfo.state = task.state
        end
        if not showMainTask then
            local branchTaskList = self:GetBranchTaskList()
            local branchT = {}
            if branchTaskList then
                for i = 1,#branchTaskList do
                    local taskId = branchTaskList[i].refId
                    local cfg = GameTable.MissionRef[taskId]
                    if cfg then
                        local state = self:GetQuestState(taskId)
                        local progress,goal = self:GetQuestProgress(taskId)
                        local sort = 2
                        if state == RewardStateEnums.CanGet then
                            sort = 3
                        elseif state == RewardStateEnums.HadGet then
                            sort = 1
                        end
                        table.insert(branchT,{taskId = taskId,taskDes = I18nText(cfg.description),sortId = cfg.sort, progress = progress,goal = goal,sort = sort,state = state})
                    end
                end
            end
            table.sort(branchT,function(a,b)
                if a.sort == b.sort then
                    return a.sortId < b.sortId
                else
                    return a.sort > b.sort
                end
            end)
            local task = branchT[1]
            if task then
                if task.state ~= RewardStateEnums.CanGet then
                    task = mainT[1] or branchT[1]
                end
                local color
                if task.state == RewardStateEnums.Normal then
                    color = "#ff6666"
                else
                    color = "#15660a"
                end
                showTaskInfo.showTaskInfo = string.replace(I18nText(10002),task.taskDes,color,task.progress,task.goal)
                showTaskInfo.questTaskId = task.taskId
                showTaskInfo.state = task.state
            end
        end
    else
        local chapterId = self:GetChapterTaskId()
        local chapterRef = GameTable.QuestStoryRef[chapterId]
        local checkChapterFinish = self:CheckChapterTaskFinish(chapterId)
        if checkChapterFinish then --剧情任务
            showTaskInfo.showTaskInfo = I18nText(chapterRef.description)
            showTaskInfo.chapterTaskId = chapterId
            showTaskInfo.state = RewardStateEnums.CanGet
        else
            local taskList = {}
            local questions = chapterRef and chapterRef.questions or false
            if questions then
                for i = 1,#questions do
                    local taskId = checknumber(questions[i])
                    local cfg = GameTable.MissionRef[taskId]
                    if cfg then
                        local state = self:GetQuestState(taskId)
                        local progress,goal = self:GetQuestProgress(taskId)
                        local sort = 2
                        if state == RewardStateEnums.CanGet then
                            sort = 3
                        elseif state == RewardStateEnums.HadGet then
                            sort = 1
                        end
                        table.insert(taskList,{taskId = taskId,taskDes = I18nText(cfg.description),sortId = cfg.sort, progress = progress,goal = goal,sort = sort,state = state})
                    end
                end
                table.sort(taskList,function(a,b)
                    if a.sort == b.sort then
                        return a.sortId < b.sortId
                    else
                        return a.sort > b.sort
                    end
                end)
                local task = taskList[1]
                local color
                if task.state == RewardStateEnums.Normal then
                    color = "#ff6666"
                else
                    color = "#15660a"
                end
                showTaskInfo.showTaskInfo = string.replace(I18nText(10002),task.taskDes,color,task.progress,task.goal)
                showTaskInfo.questTaskId = task.taskId
                showTaskInfo.state = task.state
            else
                showTaskInfo.showTaskInfo = ""
            end
        end
    end
    return showTaskInfo
end

function LxQuestCtrl:GetRedNum()
    local redNum = self:ChapterTaskRedNum() + self:MainBranchTaskRedNum() + self:DailyTaskRedNum() + self:TimeLimitedTaskRedNum()
    return redNum
end

function LxQuestCtrl:GetTaskTypeRed(taskType)
    if taskType == QuestTypeEnum.PlotTask then
        return self:ChapterTaskRedNum() > 0
    elseif taskType == QuestTypeEnum.Main then
        return self:MainBranchTaskRedNum() > 0
    elseif taskType == QuestTypeEnum.BranchLine then
        return self:MainBranchTaskRedNum() > 0
    elseif taskType == QuestTypeEnum.Daily then
        return self:DailyTaskRedNum() > 0
    elseif taskType == QuestTypeEnum.TimeLimited then
        return self:TimeLimitedTaskRedNum() > 0
    end
    return false
end

--剧情任务红点
function LxQuestCtrl:ChapterTaskRedNum()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.ChapterTask) then
        return 0
    end
    if self:CheckFinallyAllChapterTask() then
        return 0
    end
    local chapterId = self:GetChapterTaskId()
    local chapterRef = GameTable.QuestStoryRef[chapterId]
    local checkChapterFinish = self:CheckChapterTaskFinish(chapterId)
    local showTaskInfo = {}
    if checkChapterFinish then
        return 1
    else
        local questions = chapterRef and chapterRef.questions or false
        if questions then
            for i = 1,#questions do
                local taskId = checknumber(questions[i])
                local cfg = GameTable.MissionRef[taskId]
                if cfg then
                    local state = self:GetQuestState(taskId)
                    if state == RewardStateEnums.CanGet then
                        return 1
                    end
                end
            end
        end
    end
    return 0
end

--主线支线红点
function LxQuestCtrl:MainBranchTaskRedNum()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.MainBranch) then
        return 0
    end
    local task = self:GetMainTaskInfo()
    if task and task.state == RewardStateEnums.CanGet then
        return 1
    end

    local branchTaskList = self:GetBranchTaskList()
    for i = 1,#branchTaskList do
        local task = branchTaskList[i]
        if task.state == RewardStateEnums.CanGet then
            return 1
        end
    end
    return 0
end

--日常任务红点
function LxQuestCtrl:DailyTaskRedNum()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.DailyTask) then
        return 0
    end
    local dailyTaskList = self:GetDailyTaskList()
    for i = 1,#dailyTaskList do
        local task = dailyTaskList[i]
        if task.state == RewardStateEnums.CanGet then
            return 1
        end
    end
    local scoreTaskList = self:GetDailyScoreTaskList()
    for i = 1,#scoreTaskList do
        local task = scoreTaskList[i]
        if task.state == RewardStateEnums.CanGet then
            return 1
        end
    end
    return 0
end

