-- 主线任务
function LxQuestCtrl:GetMainTaskInfo()
    local mainList = {}
    local questList = ModuleCenter.Quest:GetQuestList()
    for k,v in pairs(questList) do
        local ref = GameTable.MissionRef[v.refId]
        if ref.type == QuestTypeEnum.Main then
            local taskId = v.refId
            local cfg = GameTable.MissionRef[taskId]
            if cfg then
                local state = self:GetQuestState(taskId)
                local sort = 2
                if state == RewardStateEnums.CanGet then
                    sort = 3
                elseif state == RewardStateEnums.HadGet then
                    sort = 1
                end
                table.insert(mainList,{cfgSort = cfg.sort,sort = sort,state = state,taskInfo = v})
            end
        end
    end
    table.sort(mainList,function(a,b)
        if a.sort == b.sort then
            return a.cfgSort < b.cfgSort
        else
            return a.sort > b.sort
        end
    end)
    return mainList[1] and mainList[1].taskInfo or false
