    --         return v
    --     end
    -- end
    -- return false
end

-- 支线任务列表
function LxQuestCtrl:GetBranchTaskList()
    local branchList = {}
    local questList = ModuleCenter.Quest:GetQuestList()
    for k,v in pairs(questList) do
        local ref = GameTable.MissionRef[v.refId]
        if ref.type == QuestTypeEnum.BranchLine then
            table.insert(branchList,v)
        end
    end
    return branchList
end

