----任务跳转
function LxQuestCtrl:JumpToInfo(funcId,questId)
    if not CtrlCenter.FuncOpen:IsFuncOpen(funcId, FuncOpenTipsEnum.Normal) then
        return
    end

    local ref = GameTable.FunctionMgrRef[funcId]
    if ref then
        local jumpType = ref.jumpType
        if jumpType == FuncJumpType.JumpTwo then
            
            if IsOpenPanel(UiNames.BuildStove) then
                if IsOpenPanel(UiNames.BuildCreateTwo) then
                    local uiCtrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.BuildCreateTwo)
                    if uiCtrl then
                        uiCtrl:SetRetCameraState(false)
                    end
                end
                local uiCtrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.BuildStove)
                if uiCtrl then
                    uiCtrl:SetRetCameraState(false)
                end
            end

            if IsOpenPanel(UiNames.MilitaryInstit) then
                local uiCtrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.MilitaryInstit)
                if uiCtrl then
                    uiCtrl:SetRetCameraState(false)
                end
            end
            MgrCenter.PanelMgr:CloseAllOrdinaryView()
        end
        CtrlCenter.Guide:DoTrigger(4,questId)

        --活动跳转相关
        if jumpType == FuncJumpType.JumpThree then
            if ref.jumpValue == nil then
                return
            end

            local actModelId = checknumber(ref.jumpValue[1])
            if ActivityModelToUiName[actModelId] then
                local info = ModuleCenter.Activity:GetActivityInfoByType(actModelId)
                if info ~= nil then
                    local type = info.type
                    --独立入口
                    if type == RightEnterType.Independent then
                        ShowPanel(ActivityModelToUiName[actModelId], {refId = info.refId})
                    elseif type == RightEnterType.Shop then
                        ShowPanel(UiNames.PayMain,{jumpSubType = info.refId})
                    elseif type == RightEnterType.Activity or type == RightEnterType.Welfare or type == RightEnterType.TimeLimit then
                        ShowPanel(UiNames.ActivityFrame,{type = type, jumpSubType = info.refId})
                    end
                end
            end
            return
        end

        if BuildFuncOpenIds[funcId] then --打开建筑界面跳转
            local buildId = BuildFuncOpenIds[funcId]
            local jumpFunc = function(delayTime)
                CtrlCenter.City:MoveToBuildObjPanel(buildId,false,not delayTime)
            end
            if MgrCenter.LevelMgr:IsInLevel(LevelNames.Main) then
                jumpFunc(true)
            else
                CtrlCenter.Main:GoHome({jumpFunc = jumpFunc})
            end
            return
        end
        if WorldFuncSearchIds[funcId] then
            local searchLevel = 1
            local searchRefId = WorldFuncSearchIds[funcId]
            local questRef = GameTable.MissionRef[questId]
            local finishCondArr = string.split(questRef.finish, "=")
            if WorldQuestEventHasLevelIds[checknumber(finishCondArr[1])] then
                local levelStr = string.split(finishCondArr[2], ",")
                searchLevel = tonumber(levelStr[2] or 1)
            end
            CtrlCenter.World:GoWorld({searchRefId = searchRefId, searchLevel = searchLevel})
            return
        end
        
        local uiNameInfo = _JumpToUiNames[funcId]
        if uiNameInfo then --正常打开界面
            ShowPanel(uiNameInfo.uiName, uiNameInfo.params)
            return
        end
        
        if funcId == FuncIds.Guild then
            CtrlCenter.Guild:OpenGuild()
            return
        elseif funcId == FuncIds.Ins then
            CtrlCenter.FightIdle:ChangeFightIdleMap()
        elseif funcId == FuncIds.CityMonster then
            local itemOrigin = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.ItemOrigin)
            local delay = 0
            if(itemOrigin ~= nil)then
                delay = 0.5
            end
            MgrCenter.PanelMgr:CloseAllOrdinaryView()
            if(self._jumpToCityMonsterTimer)then
                MgrCenter.TimerMgr:RemoveTimer(self._jumpToCityMonsterTimer)
            end
            self._jumpToCityMonsterTimer = MgrCenter.TimerMgr:DelayTime(function()
                ---定位到第一个解开迷雾的怪物（2025.11.13 黄江要求）
                local firstId = CtrlCenter.Role:GetFirstMonsterId()
                local monsterUnit = CtrlCenter.City:GetCityMonster(firstId)
                if monsterUnit then
                    monsterUnit:ExecuteClick();
                end
            end,self,delay,false)

            local questRef = GameTable.MissionRef[questId]
            if questRef then
                -----定位到第一个解开迷雾的怪物（2025.11.13 黄江要求）
                --local firstId = CtrlCenter.Role:GetFirstMonsterId()
                --local monsterUnit = CtrlCenter.City:GetCityMonster(firstId)
                --if monsterUnit then
                --    monsterUnit:ExecuteClick();
                --end

                --local finishCondArr = string.split(questRef.finish, "=")
                --local strArr = string.split(finishCondArr[2], ",")
                --for i = 2,#strArr do
                --    local monsterId = checknumber(strArr[i])
                --    local monsterUnit = CtrlCenter.City:GetCityMonster(monsterId)
                --    if monsterUnit then
                --
                --        monsterUnit:ExecuteClick();
                --        --CtrlCenter.City:GetCityView():SetCameraPos(monsterUnit._monsterTrans.position)
                --        --ShowPanel(UiNames.CityMonsterMenu,{refId = monsterId})
                --        break
                --    end
                --end
            end
        end
    end
end

-- 获取当前展示的限时民心任务配置
function LxQuestCtrl:GetLimitPopularRef()
    local isOpen = CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.LimitPurple)
    if not isOpen then
        return
    end
    local refList = GameTable.QuestTmieRef
    local peopleTimes = ModuleCenter.Quest:GetPeopleTimes()
    for _, v in ipairs(refList) do
        if CtrlCenter.FuncOpen:CheckConditions(v.open) then
            if not peopleTimes[v.refId] then
                return v
            end
        end
    end
end

-- 获取限时任务
function LxQuestCtrl:GetTimeLimitedTaskList()
    local showList = {}
    local lists = ModuleCenter.Quest:GetTimeLimitedList()
    for k,v in pairs(lists) do
        local ref = GameTable.QuestTimeLimitRef[v.refId]
        if ref then
            table.insert(showList,v)
        end
    end
    return showList
end

--限时任务红点
function LxQuestCtrl:TimeLimitedTaskRedNum()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.TimeLimitTask) then
        return 0
    end
    local timeLimitList = self:GetTimeLimitedTaskList()
    for i = 1,#timeLimitList do
        local task = timeLimitList[i]
        if task.state == RewardStateEnums.CanGet then
            return 1
        end
    end
    return 0
end

function LxQuestCtrl:GetTimeLimitTaskId()
    local showLimitIds = {}
    local timeLimitList = self:GetTimeLimitedTaskList()
    for i = 1,#timeLimitList do
        local task = timeLimitList[i]
        if task.state ~= RewardStateEnums.HadGet then
            table.insert(showLimitIds,task.refId)
        end
    end
    table.sort(showLimitIds,function(a,b)
        return a < b
    end)
    return showLimitIds[1]
end

function LxQuestCtrl:GetTimeLimitTaskInfo()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.TimeLimitTask) then
        return false
    end
    local taskId = self:GetTimeLimitTaskId()
    local taskInfo = ModuleCenter.Quest:GetTimeLimitTask(taskId)
    return taskInfo
end

function LxQuestCtrl:CheckHasTimeLimitedTaskInfo()
    local timeLimitList = self:GetTimeLimitedTaskList()
    return #timeLimitList > 0
end

return LxQuestCtrl